/**
 * Render a sidebar icon by name with optional size override.
 *
 * @param  string $name  Icon key from $sidebar_icons
 * @param  int    $size  Desired width/height in px (default 20)
 * @return string        SVG markup or empty string if not found
 */
function cf_icon($name, $size = 20) {
    global $sidebar_icons;
    if (!isset($sidebar_icons[$name])) return '';
    return str_replace(
        ['width="24"', 'height="24"'],
        ['width="'.$size.'"', 'height="'.$size.'"'],
        $sidebar_icons[$name]
    );
}
